// Solution
function isValidRefName(refName) {
    // Check if the ref name is empty
    if (!refName) return false;
    // Check if the ref name starts or ends with a dot, dash, or underscore
    if (refName[0] === '.' || refName[0] === '_' || refName[0] === '-' || refName[refName.length - 1] === '.' || refName[refName.length - 1] === '_' || refName[refName.length - 1] === '-') return false;
    // Check if the ref name length is between 1 and 63 characters
    if (refName.length < 1 || refName.length > 63) return false;
    // Check if the ref name contains any invalid characters
    for (let char of refName) {
        if (!char.match(/[a-zA-Z0-9._-]/)) return false;
    }
    // Return true if the ref name is valid
    return true;
}

