class Solution:
    def is_valid_ref_name(self, ref_name: str) -> bool:
        # Check if the ref name is empty
        if not ref_name: return False;
        # Check if the ref name starts or ends with a dot, dash, or underscore
        if ref_name[0] in ['.', '_', '-'] or ref_name[-1] in ['.', '_', '-']:
            return False;
        # Check if the ref name length is between 1 and 63 characters
        if len(ref_name) < 1 or len(ref_name) > 63:
            return False;
        # Check if the ref name contains any invalid characters
        for char in ref_name:
            if not char.isalnum() and char not in ['.', '_', '-']:
                return False;
        # Return true if the ref name is valid
        return True;
